{
  "mode": "All",
  "displayName": "Deploy Log Analytics agent to Windows VMs",
  "parameters": {
    "logAnalyticsWorkspaceId": {
      "type": "String",
      "metadata": { "displayName": "Log Analytics workspace resource ID" }
    }
  },
  "policyRule": {
    "if": {
      "allOf": [
        { "field": "type", "equals": "Microsoft.Compute/virtualMachines" },
        { "field": "Microsoft.Compute/virtualMachines/storageProfile.osDisk.osType", "like": "Windows*" }
      ]
    },
    "then": {
      "effect": "deployIfNotExists",
      "details": {
        "type": "Microsoft.Compute/virtualMachines/extensions",
        "name": "MicrosoftMonitoringAgent",
        "existenceCondition": {
          "allOf": [
            { "field": "Microsoft.Compute/virtualMachines/extensions/publisher", "equals": "Microsoft.EnterpriseCloud.Monitoring" },
            { "field": "Microsoft.Compute/virtualMachines/extensions/provisioningState", "equals": "Succeeded" }
          ]
        },
        "roleDefinitionIds": [
          "/providers/Microsoft.Authorization/roleDefinitions/b24988ac-6180-42a0-ab88-20f7382dd24c"
        ],
        "deployment": {
          "properties": {
            "mode": "incremental",
            "parameters": {
              "vmName":      { "value": "[field('name')]" },
              "location":    { "value": "[field('location')]" },
              "workspaceId": { "value": "[parameters('logAnalyticsWorkspaceId')]" }
            },
            "template": {
              "$schema": "https://schema.management.azure.com/schemas/2019-04-01/deploymentTemplate.json#",
              "contentVersion": "1.0.0.0",
              "parameters": {
                "vmName":      { "type": "string" },
                "location":    { "type": "string" },
                "workspaceId": { "type": "string" }
              },
              "resources": [{
                "type": "Microsoft.Compute/virtualMachines/extensions",
                "apiVersion": "2023-03-01",
                "name": "[concat(parameters('vmName'), '/MicrosoftMonitoringAgent')]",
                "location": "[parameters('location')]",
                "properties": {
                  "publisher": "Microsoft.EnterpriseCloud.Monitoring",
                  "type": "MicrosoftMonitoringAgent",
                  "typeHandlerVersion": "1.0",
                  "autoUpgradeMinorVersion": true,
                  "settings": { "workspaceId": "[parameters('workspaceId')]" }
                }
              }]
            }
          }
        }
      }
    }
  }
}

# dine-policy.tf

# The policy definition JSON is typically stored in a local file
# to avoid embedding the large template inline in HCL
resource "azurerm_policy_definition" "deploy_law_agent" {
  name         = "deploy-law-agent-windows"
  policy_type  = "Custom"
  mode         = "All"
  display_name = "Deploy Log Analytics agent to Windows VMs"
  management_group_id = var.corp_mg_id

  # Load the full DINE policy JSON from a local file
  policy_rule = file("${path.module}/policies/deploy-law-agent-rule.json")
  parameters  = file("${path.module}/policies/deploy-law-agent-params.json")
}

resource "azurerm_management_group_policy_assignment" "deploy_law_agent" {
  name                 = "deploy-law-agent-windows"
  display_name         = "Deploy Log Analytics agent to Windows VMs"
  policy_definition_id = azurerm_policy_definition.deploy_law_agent.id
  management_group_id  = var.corp_mg_id

  # DINE ALWAYS requires managed identity
  identity {
    type = "SystemAssigned"
  }
  location = var.primary_location

  parameters = jsonencode({
    logAnalyticsWorkspaceId = { value = var.law_workspace_id }
  })
}

# Grant managed identity Contributor at the MG scope
resource "azurerm_role_assignment" "dine_policy_mi" {
  scope                = var.corp_mg_id
  role_definition_name = "Contributor"
  principal_id         = azurerm_management_group_policy_assignment.deploy_law_agent.identity[0].principal_id
  depends_on           = [azurerm_management_group_policy_assignment.deploy_law_agent]
}

// DINE policy to deploy diagnostic settings to Key Vaults
{
  "mode": "All",
  "displayName": "Deploy diagnostic settings for Key Vault to Log Analytics",
  "parameters": {
    "logAnalyticsWorkspaceId": { "type": "String" }
  },
  "policyRule": {
    "if": { "field": "type", "equals": "Microsoft.KeyVault/vaults" },
    "then": {
      "effect": "deployIfNotExists",
      "details": {
        "type": "Microsoft.Insights/diagnosticSettings",
        "name": "kv-diag-law",
        "existenceCondition": {
          "field": "Microsoft.Insights/diagnosticSettings/workspaceId",
          "equals": "[parameters('logAnalyticsWorkspaceId')]"
        },
        "roleDefinitionIds": [
          "/providers/Microsoft.Authorization/roleDefinitions/b24988ac-6180-42a0-ab88-20f7382dd24c"
        ],
        "deployment": {
          "properties": {
            "mode": "incremental",
            "parameters": {
              "kvName":       { "value": "[field('name')]" },
              "kvResourceId": { "value": "[field('id')]" },
              "location":     { "value": "[field('location')]" },
              "workspaceId":  { "value": "[parameters('logAnalyticsWorkspaceId')]" }
            },
            "template": {
              "$schema": "https://schema.management.azure.com/schemas/2019-04-01/deploymentTemplate.json#",
              "contentVersion": "1.0.0.0",
              "parameters": {
                "kvName":       { "type": "string" },
                "kvResourceId": { "type": "string" },
                "location":     { "type": "string" },
                "workspaceId":  { "type": "string" }
              },
              "resources": [{
                "type": "Microsoft.Insights/diagnosticSettings",
                "apiVersion": "2021-05-01-preview",
                "name": "kv-diag-law",
                "scope": "[parameters('kvResourceId')]",
                "location": "[parameters('location')]",
                "properties": {
                  "workspaceId": "[parameters('workspaceId')]",
                  "logs": [
                    { "category": "AuditEvent", "enabled": true },
                    { "category": "AzurePolicyEvaluationDetails", "enabled": true }
                  ]
                }
              }]
            }
          }
        }
      }
    }
  }
}
